import re
from datetime import datetime, timedelta

def check_bing_staleness(grounding_data: str) -> bool:
    date_pattern = r'(\d{4}-\d{2}-\d{2})'
    dates = re.findall(date_pattern, grounding_data)
    for date_str in dates:
        try:
            pub_date = datetime.strptime(date_str, '%Y-%m-%d')
            if datetime.now() - pub_date > timedelta(days=30):
                return True  # Stale content detected
        except ValueError:
            continue
    return False

