from azure.ai.contentsafety import ContentSafetyClient

class PolicyMiddleware:
    def __init__(self):
        self.client = ContentSafetyClient(
            endpoint="https://your-safety-endpoint.cognitiveservices.azure.com/",
            credential=AzureKeyCredential("your-key")
        )

    def filter_output(self, agent_response: str) -> str:
        analysis = self.client.analyze_text(text=agent_response)
        if any(cat.severity in ["High", "Medium"] for cat in analysis.categories):
            return "Response blocked by enterprise policy"
        return agent_response

# Integrate in agent pipeline
