def filter_fresh_grounding(grounding_results: list) -> list:
    fresh_results = []
    for result in grounding_results:
        if 'published_date' in result.metadata:
            pub_date = datetime.fromisoformat(result.metadata['published_date'])
            if datetime.now() - pub_date <= timedelta(days=30):
                fresh_results.append(result)
    return fresh_results

# Apply to Azure AI Agent Service grounding
agent_config = {
    'grounding': {
        'sources': [filter_fresh_grounding(bing_results)]
    }
}

